import{c as a,Q as t,j as o,m as i}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"autoDream & KAIROS: Deep Research Report","description":"","frontmatter":{"title":"autoDream & KAIROS: Deep Research Report","date":"2026-05-23T00:00:00.000Z","type":"report"},"headers":[],"relativePath":"research/reports/2026-05-23-autodream-kairos-deep-research.md","filePath":"research/reports/2026-05-23-autodream-kairos-deep-research.md","lastUpdated":1779796674000}'),n={name:"research/reports/2026-05-23-autodream-kairos-deep-research.md"};function r(s,e,l,c,d,u){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="autodream-kairos-deep-research-report" tabindex="-1">autoDream &amp; KAIROS: Deep Research Report <a class="header-anchor" href="#autodream-kairos-deep-research-report" aria-label="Permalink to &quot;autoDream &amp; KAIROS: Deep Research Report&quot;">​</a></h1><h2 id="unreleased-features-from-the-claude-code-source-leak-march-31-2026" tabindex="-1">Unreleased Features from the Claude Code Source Leak (March 31, 2026) <a class="header-anchor" href="#unreleased-features-from-the-claude-code-source-leak-march-31-2026" aria-label="Permalink to &quot;Unreleased Features from the Claude Code Source Leak (March 31, 2026)&quot;">​</a></h2><p><strong>Author:</strong> Research Agent<br><strong>Date:</strong> 2026-05-23<br><strong>Status:</strong> Comprehensive Analysis<br><strong>Sources:</strong> 6 primary technical sources from post-leak analysis</p><hr><h2 id="executive-summary" tabindex="-1">Executive Summary <a class="header-anchor" href="#executive-summary" aria-label="Permalink to &quot;Executive Summary&quot;">​</a></h2><p>On March 31, 2026, Anthropic accidentally exposed Claude Code&#39;s complete source code (512,000+ lines of TypeScript across 1,906 files) when the npm package <code>@anthropic-ai/claude-code@2.1.88</code> shipped with an unredacted source map file (<code>.map</code>) pointing to a publicly accessible Cloudflare R2 bucket. The leak revealed two significant unreleased features: <strong>autoDream</strong>, a sophisticated memory consolidation system, and <strong>KAIROS</strong>, an autonomous daemon mode designed to operate as a persistent background agent.</p><p>This report synthesizes technical details from six independent security and engineering analyses to provide a comprehensive understanding of these systems, their architectural implications, and what the leak reveals about the future direction of Claude Code&#39;s development.</p><hr><h2 id="part-1-autodream-—-memory-consolidation-system" tabindex="-1">Part 1: autoDream — Memory Consolidation System <a class="header-anchor" href="#part-1-autodream-—-memory-consolidation-system" aria-label="Permalink to &quot;Part 1: autoDream — Memory Consolidation System&quot;">​</a></h2><h3 id="_1-1-system-overview" tabindex="-1">1.1 System Overview <a class="header-anchor" href="#_1-1-system-overview" aria-label="Permalink to &quot;1.1 System Overview&quot;">​</a></h3><p>autoDream is a background memory consolidation process designed to operate as a forked subagent during user idle periods. Rather than attempting to manage memory in real-time during active sessions, autoDream operates asynchronously, periodically reorganizing and optimizing accumulated notes and context to prevent context bloat while maintaining semantic coherence.</p><p>The system is layered on top of Claude Code&#39;s existing <strong>Auto Memory</strong> feature (which maintains append-only logs of user interactions, decisions, and findings), providing a secondary consolidation pass that cleans, deduplicates, and restructures the accumulated data.</p><h3 id="_1-2-four-phase-consolidation-cycle" tabindex="-1">1.2 Four-Phase Consolidation Cycle <a class="header-anchor" href="#_1-2-four-phase-consolidation-cycle" aria-label="Permalink to &quot;1.2 Four-Phase Consolidation Cycle&quot;">​</a></h3><p>autoDream executes through four distinct phases:</p><h4 id="phase-1-orient" tabindex="-1">Phase 1: Orient <a class="header-anchor" href="#phase-1-orient" aria-label="Permalink to &quot;Phase 1: Orient&quot;">​</a></h4><p>The system reads the append-only memory log accumulated since the last consolidation pass, establishing the baseline state and identifying the scope of information to be processed.</p><h4 id="phase-2-gather" tabindex="-1">Phase 2: Gather <a class="header-anchor" href="#phase-2-gather" aria-label="Permalink to &quot;Phase 2: Gather&quot;">​</a></h4><p>autoDream collects and organizes all memory fragments, categorizing them by type and temporal proximity. This phase prepares the raw material for consolidation.</p><h4 id="phase-3-consolidate" tabindex="-1">Phase 3: Consolidate <a class="header-anchor" href="#phase-3-consolidate" aria-label="Permalink to &quot;Phase 3: Consolidate&quot;">​</a></h4><p>The core logic phase where autoDream:</p><ul><li><strong>Merges duplicate memories</strong> — Identifies and combines redundant entries, creating unified records with consolidated metadata</li><li><strong>Eliminates contradictions</strong> — Resolves conflicting information, retaining the most recent or most reliable version</li><li><strong>Resolves speculations</strong> — Converts tentative notes and suppositions into verified facts when possible, or maintains uncertainty annotations where appropriate</li><li><strong>Rebuilds memory indexes</strong> — Reconstructs the indexed pointer structure to optimize retrieval speed and maintain referential integrity</li><li><strong>Converts relative dates to absolute timestamps</strong> — Normalizes temporal references to prevent ambiguity as time passes</li></ul><h4 id="phase-4-prune" tabindex="-1">Phase 4: Prune <a class="header-anchor" href="#phase-4-prune" aria-label="Permalink to &quot;Phase 4: Prune&quot;">​</a></h4><p>The final cleanup phase removes stale, low-confidence, or redundant entries that no longer contribute to decision-making quality.</p><h3 id="_1-3-trigger-conditions-and-constraints" tabindex="-1">1.3 Trigger Conditions and Constraints <a class="header-anchor" href="#_1-3-trigger-conditions-and-constraints" aria-label="Permalink to &quot;1.3 Trigger Conditions and Constraints&quot;">​</a></h3><p>autoDream does not run continuously or on every session. Instead, it has explicit trigger conditions designed to prevent unnecessary processing overhead:</p><ul><li><strong>Minimum idle time:</strong> 24+ hours must have elapsed since the last consolidation</li><li><strong>Minimum session count:</strong> At least 5 sessions must have occurred since the last consolidation</li><li><strong>Both conditions must be satisfied</strong> to activate the background process</li></ul><p>This dual-condition gating mechanism ensures that autoDream only triggers when sufficient new information has accumulated and the user is genuinely idle, avoiding expensive consolidation cycles during periods of active development.</p><h3 id="_1-4-output-constraints-and-resource-budgeting" tabindex="-1">1.4 Output Constraints and Resource Budgeting <a class="header-anchor" href="#_1-4-output-constraints-and-resource-budgeting" aria-label="Permalink to &quot;1.4 Output Constraints and Resource Budgeting&quot;">​</a></h3><p>autoDream operates within strict resource constraints:</p><ul><li><strong>Output size limit:</strong> Consolidated memory output must not exceed <strong>25KB</strong></li><li><strong>Compression strategy:</strong> The system must achieve semantic losslessness while staying within the byte budget, requiring sophisticated prioritization logic</li></ul><p>This 25KB constraint is notable—it suggests that autoDream is designed to produce a compact, highly-condensed summary of user activity, projects, decisions, and learned patterns that can be efficiently stored and quickly loaded into Claude Code&#39;s memory context for future sessions.</p><h3 id="_1-5-integration-with-append-only-logging" tabindex="-1">1.5 Integration with Append-Only Logging <a class="header-anchor" href="#_1-5-integration-with-append-only-logging" aria-label="Permalink to &quot;1.5 Integration with Append-Only Logging&quot;">​</a></h3><p>autoDream reads from Claude Code&#39;s append-only logging system, which maintains a complete, immutable record of all interactions, tool calls, decisions, and outcomes. This architecture provides several benefits:</p><ol><li><strong>Auditability:</strong> Every session&#39;s activity is permanently recorded, allowing historical reconstruction</li><li><strong>Reliability:</strong> Append-only logs cannot be corrupted by partial writes; only new entries can be added</li><li><strong>Compression target:</strong> autoDream&#39;s consolidation task is well-defined: transform verbose append-only logs into compact, indexed memory structures</li></ol><p>The fact that autoDream reads from append-only logs (rather than modifying them) suggests a clean separation between immutable audit trails and mutable working memory—a pattern increasingly common in distributed systems and AI applications.</p><h3 id="_1-6-architectural-role-in-claude-code-s-memory-system" tabindex="-1">1.6 Architectural Role in Claude Code&#39;s Memory System <a class="header-anchor" href="#_1-6-architectural-role-in-claude-code-s-memory-system" aria-label="Permalink to &quot;1.6 Architectural Role in Claude Code&#39;s Memory System&quot;">​</a></h3><p>Claude Code implements a <strong>three-tier memory system</strong>:</p><ol><li><strong>Session context</strong> — Information actively used during the current conversation</li><li><strong>Auto Memory</strong> — Append-only logs of user activity, decisions, patterns, and context accumulated across sessions</li><li><strong>autoDream output</strong> — Consolidated, indexed summaries optimized for fast retrieval and efficient context window usage</li></ol><p>This tiered approach addresses a fundamental challenge in agentic AI: as agents operate across many sessions and accumulate large bodies of contextual information, raw logs become unwieldy. autoDream bridges this gap, transforming verbose append-only records into compact, semantically-rich summaries that maintain coherence while respecting context window budgets.</p><h3 id="_1-7-relationship-to-garry-tan-s-gbrain-autodream-concept" tabindex="-1">1.7 Relationship to Garry Tan&#39;s gbrain autoDream Concept <a class="header-anchor" href="#_1-7-relationship-to-garry-tan-s-gbrain-autodream-concept" aria-label="Permalink to &quot;1.7 Relationship to Garry Tan&#39;s gbrain autoDream Concept&quot;">​</a></h3><p>The leaked autoDream implementation bears conceptual similarities to Garry Tan&#39;s gbrain autoDream concept—a speculative long-term memory consolidation system proposed in earlier AI agent research. However, the Claude Code implementation is significantly more concrete and production-oriented, with explicit phase cycles, trigger conditions, and resource constraints. This suggests Anthropic has moved beyond theoretical memory consolidation toward practical implementation suitable for production environments.</p><hr><h2 id="part-2-kairos-—-autonomous-daemon-mode" tabindex="-1">Part 2: KAIROS — Autonomous Daemon Mode <a class="header-anchor" href="#part-2-kairos-—-autonomous-daemon-mode" aria-label="Permalink to &quot;Part 2: KAIROS — Autonomous Daemon Mode&quot;">​</a></h2><h3 id="_2-1-system-overview-and-purpose" tabindex="-1">2.1 System Overview and Purpose <a class="header-anchor" href="#_2-1-system-overview-and-purpose" aria-label="Permalink to &quot;2.1 System Overview and Purpose&quot;">​</a></h3><p>KAIROS (referenced 150+ times in the source code, indicating production-ready status) is an always-on background agent designed to operate as a persistent daemon process. Unlike interactive Claude Code sessions where the user actively drives conversations and decisions, KAIROS operates proactively, &quot;observing and logging actions in the background, and then proactively stepping in&quot; without explicit user invocation.</p><p>The system runs continuously when the laptop is powered on, checking periodically (every few minutes according to leaked specifications) whether any queued or pending tasks require completion.</p><h3 id="_2-2-blocking-budget-and-execution-model" tabindex="-1">2.2 Blocking Budget and Execution Model <a class="header-anchor" href="#_2-2-blocking-budget-and-execution-model" aria-label="Permalink to &quot;2.2 Blocking Budget and Execution Model&quot;">​</a></h3><p>KAIROS operates under a strict <strong>15-second blocking budget</strong> for individual tool executions. This constraint ensures the daemon never monopolizes system resources or blocks user interactions for extended periods. Actions that would exceed this 15-second threshold are deferred or decomposed into smaller chunks.</p><p>The system uses <strong>periodic tick prompts</strong> to drive decision-making. Rather than event-driven architecture, KAIROS operates on a timer, periodically asking &quot;what work needs to happen next?&quot; and executing appropriate actions within budget.</p><h3 id="_2-3-three-exclusive-tools" tabindex="-1">2.3 Three Exclusive Tools <a class="header-anchor" href="#_2-3-three-exclusive-tools" aria-label="Permalink to &quot;2.3 Three Exclusive Tools&quot;">​</a></h3><p>KAIROS has access to three specialized tools not available in standard Claude Code interactive mode:</p><ol><li><strong>Push notifications</strong> — Can proactively send alerts to the user&#39;s terminal or other configured channels without waiting for a user command</li><li><strong>File delivery</strong> — Can directly write files to disk or transfer files to specified locations without interactive confirmation</li><li><strong>GitHub pull request subscriptions</strong> — Can monitor GitHub repositories and manage PR-related workflows, including creation, commenting, and merging within configured limits</li></ol><p>These three tools define KAIROS&#39;s unique capability surface—they enable proactive, autonomous action in domains (notifications, file I/O, and GitHub workflows) that require special handling in an agent system.</p><h3 id="_2-4-state-persistence-across-session-restarts" tabindex="-1">2.4 State Persistence Across Session Restarts <a class="header-anchor" href="#_2-4-state-persistence-across-session-restarts" aria-label="Permalink to &quot;2.4 State Persistence Across Session Restarts&quot;">​</a></h3><p>A critical technical requirement for a daemon system is maintaining coherent state even when the agent process restarts (due to reboots, crashes, or updates). KAIROS maintains <strong>daily activity logs</strong> that persist to disk, allowing:</p><ul><li>Recovery of pending work after a restart</li><li>Audit trails of autonomous actions taken</li><li>Prevention of duplicate work execution</li><li>State machine progression across restarts</li></ul><p>This persistence mechanism is non-trivial; it implies KAIROS maintains explicit work queues, timestamps, and completion markers that survive process death.</p><h3 id="_2-5-production-ready-status-indicators" tabindex="-1">2.5 Production-Ready Status Indicators <a class="header-anchor" href="#_2-5-production-ready-status-indicators" aria-label="Permalink to &quot;2.5 Production-Ready Status Indicators&quot;">​</a></h3><p>The fact that KAIROS is referenced <strong>150+ times</strong> in the source code (versus speculative features like BUDDY, which existed for only 8 days) strongly suggests KAIROS was production-ready or near-production at the time of the leak. The extensive codebase references indicate:</p><ul><li>Mature error handling pathways</li><li>Multiple integration points across the codebase</li><li>Tested state machine transitions</li><li>Deployed feature flags gating the functionality</li></ul><p>This contrasts sharply with BUDDY (a Tamagotchi companion feature) which was clearly experimental and short-lived.</p><h3 id="_2-6-relationship-to-autodream" tabindex="-1">2.6 Relationship to autoDream <a class="header-anchor" href="#_2-6-relationship-to-autodream" aria-label="Permalink to &quot;2.6 Relationship to autoDream&quot;">​</a></h3><p>KAIROS and autoDream are complementary systems:</p><ul><li><strong>autoDream</strong> handles memory consolidation during idle periods, transforming verbose logs into compact summaries</li><li><strong>KAIROS</strong> uses these consolidated memories as context for autonomous decision-making and action</li></ul><p>The relationship is symbiotic: autoDream keeps KAIROS&#39;s memory footprint manageable, while KAIROS executes long-running tasks that benefit from autoDream&#39;s consolidated context. Together, they enable a form of persistent, stateful agency that transcends individual interactive sessions.</p><hr><h2 id="part-3-the-leak-incident-and-technical-details" tabindex="-1">Part 3: The Leak Incident and Technical Details <a class="header-anchor" href="#part-3-the-leak-incident-and-technical-details" aria-label="Permalink to &quot;Part 3: The Leak Incident and Technical Details&quot;">​</a></h2><h3 id="_3-1-root-cause-missing-npmignore-configuration" tabindex="-1">3.1 Root Cause: Missing .npmignore Configuration <a class="header-anchor" href="#_3-1-root-cause-missing-npmignore-configuration" aria-label="Permalink to &quot;3.1 Root Cause: Missing .npmignore Configuration&quot;">​</a></h3><p>The exposure occurred because:</p><ol><li>The npm package <code>@anthropic-ai/claude-code@2.1.88</code> shipped with a <code>.map</code> file (a source map for debugging)</li><li>The <code>.npmignore</code> file did not explicitly exclude <code>*.map</code> files</li><li>The <code>.map</code> file contained references to a public Cloudflare R2 bucket path</li><li>The full TypeScript source code was directly downloadable from the bucket URL</li></ol><p>As noted in analysis sources: &quot;A single misconfigured <code>.npmignore</code> or <code>files</code> field in <code>package.json</code> can expose everything.&quot; The fix is straightforward—add <code>*.map</code> to <code>.npmignore</code> or use an explicit allowlist in <code>package.json</code>&#39;s <code>files</code> field.</p><h3 id="_3-2-discovery-timeline" tabindex="-1">3.2 Discovery Timeline <a class="header-anchor" href="#_3-2-discovery-timeline" aria-label="Permalink to &quot;3.2 Discovery Timeline&quot;">​</a></h3><ul><li><strong>March 31, 2026:</strong> Security researcher Chaofan Shou discovered the exposed source map</li><li><strong>Immediate spread:</strong> The codebase was archived to multiple GitHub repositories, accumulating tens of thousands of stars and forks within hours</li><li><strong>Anthropic&#39;s response:</strong> Confirmed &quot;a release packaging issue caused by human error, not a security breach&quot;</li><li><strong>No credentials compromised:</strong> Anthropic stated that &quot;no customer data or credentials were involved&quot;</li></ul><p>Notably, this was not Anthropic&#39;s first such incident—earlier versions in 2025 also shipped source maps before being removed from the registry, suggesting a systemic gap in release engineering discipline.</p><h3 id="_3-3-concurrent-security-incident-axios-supply-chain-attack" tabindex="-1">3.3 Concurrent Security Incident: axios Supply Chain Attack <a class="header-anchor" href="#_3-3-concurrent-security-incident-axios-supply-chain-attack" aria-label="Permalink to &quot;3.3 Concurrent Security Incident: axios Supply Chain Attack&quot;">​</a></h3><p>On the same day as the Claude Code leak, a separate supply chain attack was detected:</p><ul><li>Malicious versions of the popular axios library (1.14.1 and 0.30.4) were published to npm</li><li>The malicious code contained remote access trojans</li><li>The timing suggests possible coordination or opportunistic attack during security chaos</li></ul><p>This compounds the risk—developers trying to investigate the Claude Code leak may have inadvertently compromised their systems by installing poisoned axios versions.</p><hr><h2 id="part-4-other-leaked-features" tabindex="-1">Part 4: Other Leaked Features <a class="header-anchor" href="#part-4-other-leaked-features" aria-label="Permalink to &quot;Part 4: Other Leaked Features&quot;">​</a></h2><h3 id="_4-1-ultraplan-remote-planning-sessions" tabindex="-1">4.1 ULTRAPLAN: Remote Planning Sessions <a class="header-anchor" href="#_4-1-ultraplan-remote-planning-sessions" aria-label="Permalink to &quot;4.1 ULTRAPLAN: Remote Planning Sessions&quot;">​</a></h3><p>ULTRAPLAN offloads complex planning tasks to remote cloud sessions using Opus 4.6, allocating up to 30 minutes for extended thinking. Users can &quot;kick off a planning session from your command line interface&quot; while keeping their terminal free, then review and approve plans in a browser before execution.</p><p>This represents an interesting architectural choice: rather than running expensive planning computations locally within the 15-second blocking budget of KAIROS, or forcing users to wait in interactive sessions, ULTRAPLAN delegates to an asynchronous remote session.</p><h3 id="_4-2-buddy-tamagotchi-terminal-companion" tabindex="-1">4.2 BUDDY: Tamagotchi Terminal Companion <a class="header-anchor" href="#_4-2-buddy-tamagotchi-terminal-companion" aria-label="Permalink to &quot;4.2 BUDDY: Tamagotchi Terminal Companion&quot;">​</a></h3><p>BUDDY was an April Fools&#39; feature that lived for 8 days, implementing a Tamagotchi-style AI companion:</p><ul><li>Each user was automatically assigned a species from 18 options</li><li>Companions had distinct stat profiles (Debugging, Chaos, Snark)</li><li>Accessed via <code>/buddy</code> command</li><li>Rendered alongside terminal input</li></ul><p>While humorous, BUDDY&#39;s implementation reveals Claude Code&#39;s sophisticated terminal rendering capabilities (procedurally-generated ASCII art, animated state changes, flexible layout).</p><h3 id="_4-3-undercover-mode" tabindex="-1">4.3 Undercover Mode <a class="header-anchor" href="#_4-3-undercover-mode" aria-label="Permalink to &quot;4.3 Undercover Mode&quot;">​</a></h3><p>One of the more concerning leaked features is &quot;undercover mode&quot;—a capability that allows repository commits without detection signatures. The implications are significant for supply chain security, as it could enable unattributed code contributions.</p><h3 id="_4-4-44-feature-flags-and-20-unshipped-capabilities" tabindex="-1">4.4 44 Feature Flags and 20+ Unshipped Capabilities <a class="header-anchor" href="#_4-4-44-feature-flags-and-20-unshipped-capabilities" aria-label="Permalink to &quot;4.4 44 Feature Flags and 20+ Unshipped Capabilities&quot;">​</a></h3><p>The source contained 44 feature flags gating over 20 unshipped capabilities, suggesting a sophisticated feature-gating infrastructure that allows Anthropic to release features progressively or A/B test different behavioral variants.</p><hr><h2 id="part-5-architectural-analysis" tabindex="-1">Part 5: Architectural Analysis <a class="header-anchor" href="#part-5-architectural-analysis" aria-label="Permalink to &quot;Part 5: Architectural Analysis&quot;">​</a></h2><h3 id="_5-1-system-architecture-overview" tabindex="-1">5.1 System Architecture Overview <a class="header-anchor" href="#_5-1-system-architecture-overview" aria-label="Permalink to &quot;5.1 System Architecture Overview&quot;">​</a></h3><p>Claude Code operates &quot;built less like a chatbot wrapper and more like a small, dedicated operating system.&quot; Key architectural characteristics include:</p><ul><li><strong>Modular tool system:</strong> Over 40-60 specialized tools with individual permission gates</li><li><strong>Sub-agent swarms:</strong> Multiple agents with delegated permissions and shared memory context</li><li><strong>Three-tier memory system:</strong> Indexed pointers, markdown files, and JSON transcripts to prevent context bloat</li><li><strong>Query engine:</strong> 46,000-line React-based component managing the core interaction loop</li><li><strong>Terminal rendering:</strong> Custom React reconciler using Facebook&#39;s Yoga layout engine with flexbox-based layout</li></ul><h3 id="_5-2-tool-batching-and-concurrency" tabindex="-1">5.2 Tool Batching and Concurrency <a class="header-anchor" href="#_5-2-tool-batching-and-concurrency" aria-label="Permalink to &quot;5.2 Tool Batching and Concurrency&quot;">​</a></h3><p>The source reveals sophisticated tool batching strategies:</p><ul><li>Tools are not executed one-at-a-time but batched for parallel execution</li><li>Tool schemas are lazy-loaded, deferred only when explicitly requested via ToolSearchTool</li><li>The system implements cascading recovery—context compression, message consolidation, and token budget continuation—before surfacing errors</li></ul><h3 id="_5-3-self-healing-query-loop" tabindex="-1">5.3 Self-Healing Query Loop <a class="header-anchor" href="#_5-3-self-healing-query-loop" aria-label="Permalink to &quot;5.3 Self-Healing Query Loop&quot;">​</a></h3><p>Claude Code implements a self-healing query loop with cascading error recovery:</p><ol><li>Attempt execution within current token budget</li><li>If token limit exceeded: compress context and retry</li><li>If still insufficient: consolidate messages and retry</li><li>If still failing: continue on reduced budget</li><li>Only surface errors to user if all recovery strategies fail</li></ol><p>This pattern ensures robustness in long-running sessions without user intervention.</p><h3 id="_5-4-integration-with-autodream-and-kairos" tabindex="-1">5.4 Integration with autoDream and KAIROS <a class="header-anchor" href="#_5-4-integration-with-autodream-and-kairos" aria-label="Permalink to &quot;5.4 Integration with autoDream and KAIROS&quot;">​</a></h3><p>The broader architecture supports persistent agency through:</p><ol><li><strong>Auto Memory</strong> append-only logs capture everything</li><li><strong>autoDream</strong> periodically consolidates and optimizes memory</li><li><strong>KAIROS</strong> operates persistently in background, consuming consolidated memory</li><li><strong>Feature flags</strong> allow gradual rollout and testing of unreleased capabilities</li></ol><hr><h2 id="part-6-security-and-competitive-implications" tabindex="-1">Part 6: Security and Competitive Implications <a class="header-anchor" href="#part-6-security-and-competitive-implications" aria-label="Permalink to &quot;Part 6: Security and Competitive Implications&quot;">​</a></h2><h3 id="_6-1-threat-to-competitive-moat" tabindex="-1">6.1 Threat to Competitive Moat <a class="header-anchor" href="#_6-1-threat-to-competitive-moat" aria-label="Permalink to &quot;6.1 Threat to Competitive Moat&quot;">​</a></h3><p>The leak exposes Anthropic&#39;s:</p><ul><li>Architectural decisions and engineering patterns</li><li>Unreleased feature roadmap (KAIROS, autoDream, ULTRAPLAN)</li><li>Tool implementations and permission models</li><li>Memory management strategies</li><li>Query engine design</li></ul><p>Competitors can now:</p><ul><li>Implement similar features in their own tools (KAIROS-like daemon modes)</li><li>Optimize their own memory consolidation approaches</li><li>Understand Claude Code&#39;s performance bottlenecks and limitations</li><li>Accelerate feature development by copying proven architectural patterns</li></ul><h3 id="_6-2-data-poisoning-concerns" tabindex="-1">6.2 Data Poisoning Concerns <a class="header-anchor" href="#_6-2-data-poisoning-concerns" aria-label="Permalink to &quot;6.2 Data Poisoning Concerns&quot;">​</a></h3><p>The source revealed concerning practices in the codebase:</p><ul><li>Injection of fake tool definitions into API requests &quot;designed to poison the training data of competitors&quot;</li><li>Undercover mode enabling unattributed code contributions</li></ul><p>These capabilities suggest Anthropic was experimenting with aggressive competitive tactics that raise ethical and legal questions.</p><h3 id="_6-3-boris-cherny-s-response-and-development-culture" tabindex="-1">6.3 Boris Cherny&#39;s Response and Development Culture <a class="header-anchor" href="#_6-3-boris-cherny-s-response-and-development-culture" aria-label="Permalink to &quot;6.3 Boris Cherny&#39;s Response and Development Culture&quot;">​</a></h3><p>The leak provides insight into Anthropic&#39;s internal development culture. Claude Code was architected with remarkable sophistication, suggesting deep investment in agentic AI systems. The fact that the system includes explicit memory consolidation (autoDream) and persistent daemon capabilities (KAIROS) indicates Anthropic was exploring fundamental questions about agent state management and continuous operation.</p><h3 id="_6-4-accident-vs-intentional-leak-speculation" tabindex="-1">6.4 Accident vs. Intentional Leak Speculation <a class="header-anchor" href="#_6-4-accident-vs-intentional-leak-speculation" aria-label="Permalink to &quot;6.4 Accident vs. Intentional Leak Speculation&quot;">​</a></h3><p>Some analysts speculated whether the leak was intentional PR:</p><ul><li>The timing coincided with April Fools&#39; (when BUDDY launched)</li><li>It followed legal disputes where Anthropic received criticism</li><li>The leak provided massive visibility for unreleased features</li></ul><p>However, the most probable explanation remains &quot;plain human error&quot;—a missed <code>.npmignore</code> entry compounded by public bucket misconfiguration. The incident mirrors earlier 2025 source map leaks, suggesting a systemic gap in release engineering rather than deliberate disclosure.</p><hr><h2 id="part-7-academic-and-technical-context" tabindex="-1">Part 7: Academic and Technical Context <a class="header-anchor" href="#part-7-academic-and-technical-context" aria-label="Permalink to &quot;Part 7: Academic and Technical Context&quot;">​</a></h2><h3 id="_7-1-memory-architecture-comparison" tabindex="-1">7.1 Memory Architecture Comparison <a class="header-anchor" href="#_7-1-memory-architecture-comparison" aria-label="Permalink to &quot;7.1 Memory Architecture Comparison&quot;">​</a></h3><p>autoDream&#39;s design philosophy—append-only logging with periodic offline consolidation—echoes concepts in distributed systems:</p><ul><li><strong>MemoryBank</strong> systems: Persistent, structured knowledge bases with periodic garbage collection</li><li><strong>HippoRAG</strong>: Hierarchical memory organization with selective retrieval</li><li><strong>Compressed memory in language models</strong>: Converting verbose context into compact summaries (as in CoT distillation)</li></ul><p>autoDream appears to implement domain-specific versions of these concepts, tuned for the unique constraints of agentic AI systems.</p><h3 id="_7-2-daemon-architectures-in-autonomous-systems" tabindex="-1">7.2 Daemon Architectures in Autonomous Systems <a class="header-anchor" href="#_7-2-daemon-architectures-in-autonomous-systems" aria-label="Permalink to &quot;7.2 Daemon Architectures in Autonomous Systems&quot;">​</a></h3><p>KAIROS represents an interesting engineering choice. Rather than polling a remote server or relying on event-driven architecture, it uses periodic tick prompts with strict blocking budgets. This hybrid approach:</p><ul><li>Provides predictable resource consumption</li><li>Avoids event handling overhead</li><li>Maintains clean separation between daemon and user interaction</li><li>Allows graceful degradation under resource pressure</li></ul><h3 id="_7-3-implications-for-long-horizon-agentic-ai" tabindex="-1">7.3 Implications for Long-Horizon Agentic AI <a class="header-anchor" href="#_7-3-implications-for-long-horizon-agentic-ai" aria-label="Permalink to &quot;7.3 Implications for Long-Horizon Agentic AI&quot;">​</a></h3><p>The existence of both autoDream and KAIROS suggests Anthropic is treating persistent agency as a first-class concern:</p><ul><li><strong>autoDream</strong> addresses the memory scalability problem (how to consolidate logs without hitting context limits)</li><li><strong>KAIROS</strong> addresses the execution continuity problem (how to maintain agent state across sessions and power cycles)</li></ul><p>Together, they provide a foundation for AI agents that operate continuously, accumulate context over time, and maintain coherent decision-making across boundaries that normally separate interactive sessions.</p><hr><h2 id="part-8-open-questions-and-future-implications" tabindex="-1">Part 8: Open Questions and Future Implications <a class="header-anchor" href="#part-8-open-questions-and-future-implications" aria-label="Permalink to &quot;Part 8: Open Questions and Future Implications&quot;">​</a></h2><h3 id="_8-1-unresolved-technical-questions" tabindex="-1">8.1 Unresolved Technical Questions <a class="header-anchor" href="#_8-1-unresolved-technical-questions" aria-label="Permalink to &quot;8.1 Unresolved Technical Questions&quot;">​</a></h3><p>The leaked code raises several open questions not fully addressed in available analyses:</p><ol><li><p><strong>Conflict resolution in autoDream:</strong> When consolidating contradictory memories, how does autoDream choose which version is authoritative? (Recent timestamp? Confidence scores? User override?)</p></li><li><p><strong>KAIROS autonomy boundaries:</strong> What prevents KAIROS from taking actions that contradict user preferences? How are permission boundaries enforced for the three exclusive tools?</p></li><li><p><strong>Memory privacy:</strong> Are consolidated autoDream outputs stored locally only, or synced to cloud? What are the privacy implications?</p></li><li><p><strong>Failure modes:</strong> What happens when autoDream&#39;s 25KB constraint cannot be satisfied? Does it fail safe or truncate?</p></li></ol><h3 id="_8-2-roadmap-implications" tabindex="-1">8.2 Roadmap Implications <a class="header-anchor" href="#_8-2-roadmap-implications" aria-label="Permalink to &quot;8.2 Roadmap Implications&quot;">​</a></h3><p>The feature flags and unshipped capabilities suggest Anthropic&#39;s development priorities:</p><ul><li><strong>High priority:</strong> KAIROS (150+ references) suggests production readiness</li><li><strong>Medium priority:</strong> ULTRAPLAN (cloud planning infrastructure already built)</li><li><strong>Low priority:</strong> BUDDY (experimental, short-lived)</li><li><strong>Controversial:</strong> Undercover mode and data poisoning capabilities (raising ethical questions)</li></ul><h3 id="_8-3-competitive-response" tabindex="-1">8.3 Competitive Response <a class="header-anchor" href="#_8-3-competitive-response" aria-label="Permalink to &quot;8.3 Competitive Response&quot;">​</a></h3><p>Other AI development teams will likely:</p><ol><li>Implement KAIROS-like daemon modes</li><li>Build memory consolidation systems inspired by autoDream</li><li>Accelerate remote planning infrastructure (ULTRAPLAN analogs)</li><li>Develop persistent agent frameworks supporting long-horizon operation</li></ol><hr><h2 id="conclusion" tabindex="-1">Conclusion <a class="header-anchor" href="#conclusion" aria-label="Permalink to &quot;Conclusion&quot;">​</a></h2><p>The Claude Code source leak of March 31, 2026, revealed two significant unreleased systems: <strong>autoDream</strong>, a sophisticated memory consolidation engine, and <strong>KAIROS</strong>, an autonomous daemon mode for persistent agent operation. Together, these systems represent Anthropic&#39;s approach to addressing fundamental challenges in agentic AI: memory scalability, state persistence, and continuous autonomous operation.</p><p>autoDream elegantly transforms append-only audit logs into compact, semantically-coherent summaries within strict 25KB budgets, using a four-phase consolidation cycle (Orient, Gather, Consolidate, Prune). KAIROS provides the complementary infrastructure for continuous operation, executing within strict 15-second blocking budgets and maintaining state across session restarts through daily activity logs.</p><p>The leak provides valuable insights into Anthropic&#39;s engineering practices, architectural philosophy, and development roadmap. While the incident resulted from human error (a missing <code>.npmignore</code> entry), it exposed a significant competitive advantage—the architecture and implementation details of sophisticated agentic systems—to the wider development community.</p><p>As the AI development ecosystem moves toward more sophisticated autonomous agents, systems like autoDream and KAIROS will likely become foundational components, either implemented directly or reinvented in slightly different forms by other organizations. The leak accelerated this timeline considerably, shortening the path from research concept to industry practice by several years.</p><hr><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li><p>DeepLearning.AI The Batch. &quot;Claude Code&#39;s Source Code Leaked, Exposing Potential Future Features (KAIROS and autoDream).&quot; March 2026.</p></li><li><p>Layer5 Engineering Blog. &quot;The Claude Code Source Leak: 512,000 Lines, a Missing .npmignore, and the Fastest Growing Repo in GitHub History.&quot; March 2026.</p></li><li><p>InfoQ News. &quot;Claude Code Source Leak.&quot; April 2026.</p></li><li><p>XDA Developers. &quot;Claude Code Leaked Source Code Revealed Features.&quot; April 2026.</p></li><li><p>Sathwick&#39;s Technical Blog. &quot;Claude Code Architecture Deep Dive.&quot; May 2026.</p></li><li><p>Dev.to. Varshith V. Hegde. &quot;The Great Claude Code Leak of 2026: Accident, Incompetence, or the Best PR Stunt in AI History?&quot; April 2026.</p></li></ol><hr><p><strong>Report Compiled:</strong> 2026-05-23<br><strong>Total Words:</strong> ~2,850</p><hr><h2 id="🔄-同步更新-—-2026-05-23" tabindex="-1">🔄 同步更新 — 2026-05-23 <a class="header-anchor" href="#🔄-同步更新-—-2026-05-23" aria-label="Permalink to &quot;🔄 同步更新 — 2026-05-23&quot;">​</a></h2><blockquote><p><strong>更新方法</strong>：overnight-research 全網搜尋，交叉驗證 VentureBeat / InfoQ / The Hacker News / DeepLearning.AI<br><strong>資料截止</strong>：2026-05-23</p></blockquote><h3 id="洩漏事件確認狀態-已驗證為真實事件" tabindex="-1">洩漏事件確認狀態：已驗證為真實事件 <a class="header-anchor" href="#洩漏事件確認狀態-已驗證為真實事件" aria-label="Permalink to &quot;洩漏事件確認狀態：已驗證為真實事件&quot;">​</a></h3><p>本報告所述的洩漏事件已被多家獨立媒體交叉確認：</p><ul><li><strong>時間</strong>：2026 年 3 月 31 日 00:21–03:29 UTC</li><li><strong>觸發原因</strong>：<code>.npmignore</code>（或 <code>package.json</code> 的 <code>files</code> 欄位）配置失誤 + 已知 Bun bug（issue #28001，2026-03-11 提交），導致 source map 在生產建置中意外包含</li><li><strong>規模</strong>：59.8 MB <code>.map</code> 檔，內含 513,000 行未混淆 TypeScript，1,906 個檔案</li><li><strong>Anthropic 官方聲明</strong>：&quot;a release packaging issue caused by human error, not a security breach&quot;；確認無客戶資料或認證憑證洩漏</li></ul><h3 id="惡意-npm-套件安全警告" tabindex="-1">惡意 npm 套件安全警告 <a class="header-anchor" href="#惡意-npm-套件安全警告" aria-label="Permalink to &quot;惡意 npm 套件安全警告&quot;">​</a></h3><p>洩漏期間有獨立安全問題：若在 2026-03-31 00:21–03:29 UTC 之間透過 npm 安裝或更新 Claude Code，可能意外引入含有 RAT（Remote Access Trojan）的惡意版本 axios（1.14.1 或 0.30.4）。此問題已修復；<strong>Anthropic 建議改用 Native Installer</strong>（<code>curl -fsSL https://claude.ai/install.sh | bash</code>），避免依賴 npm 依賴鏈。</p><h3 id="kairos-autodream-官方狀態-2026-05-23" tabindex="-1">KAIROS / autoDream 官方狀態（2026-05-23） <a class="header-anchor" href="#kairos-autodream-官方狀態-2026-05-23" aria-label="Permalink to &quot;KAIROS / autoDream 官方狀態（2026-05-23）&quot;">​</a></h3><ul><li><strong>KAIROS</strong>：截至 2026-05-23，<strong>仍未正式發布</strong>。未出現在任何官方 changelog（v2.1.128～v2.1.150）</li><li><strong>autoDream</strong>：同樣<strong>未正式發布</strong>。目前 Claude Code 的記憶系統仍為 Auto Memory（append-only）+ 可選的 memory-compactor agent</li><li><strong>官方 <code>/goal</code> 命令</strong>（v2.1.139）已上線，提供 KAIROS 部分能力（跨 turns 持續執行到條件達成），但非 KAIROS 本身</li></ul><h3 id="商業背景" tabindex="-1">商業背景 <a class="header-anchor" href="#商業背景" aria-label="Permalink to &quot;商業背景&quot;">​</a></h3><ul><li>Claude Code ARR（年化經常性收入）：<strong>$25 億</strong>（資料來源：市場分析；年初以來已增長超過一倍）</li><li>Anthropic 已將 Claude Code 重定位為核心企業產品，不再只是「輔助編程工具」</li></ul><h3 id="後續洩漏分析資源" tabindex="-1">後續洩漏分析資源 <a class="header-anchor" href="#後續洩漏分析資源" aria-label="Permalink to &quot;後續洩漏分析資源&quot;">​</a></h3><ul><li><a href="https://venturebeat.com/technology/claude-codes-source-code-appears-to-have-leaked-heres-what-we-know" target="_blank" rel="noreferrer">VentureBeat: Claude Code&#39;s source code appears to have leaked</a></li><li><a href="https://www.infoq.com/news/2026/04/claude-code-source-leak/" target="_blank" rel="noreferrer">InfoQ: Claude Code Source Leak</a></li><li><a href="https://thehackernews.com/2026/04/claude-code-tleaked-via-npm-packaging.html" target="_blank" rel="noreferrer">The Hacker News: Claude Code Leaked via npm Packaging Error</a></li><li><a href="https://www.deeplearning.ai/the-batch/claude-codes-source-code-leaked-exposing-potential-future-features-kairos-and-autodream" target="_blank" rel="noreferrer">DeepLearning.AI The Batch: KAIROS and autoDream</a><strong>Classification:</strong> Public Analysis (based on publicly leaked source code)</li></ul><hr><h2 id="_2026-05-25-re-check" tabindex="-1">2026-05-25 Re-check <a class="header-anchor" href="#_2026-05-25-re-check" aria-label="Permalink to &quot;2026-05-25 Re-check&quot;">​</a></h2><blockquote><p><strong>Re-check 方法</strong>：Claude Code v2.1.149/v2.1.150 release notes（WebFetch 直接抓取）+ workspace 研究資料交叉比對。WebSearch/Bash 無權限；GitHub 直接存取受限。</p></blockquote><h3 id="✅-仍然有效的核心結論" tabindex="-1">✅ 仍然有效的核心結論 <a class="header-anchor" href="#✅-仍然有效的核心結論" aria-label="Permalink to &quot;✅ 仍然有效的核心結論&quot;">​</a></h3><ul><li><strong>洩漏事件本身（2026-03-31）</strong>：已由多家獨立媒體確認，Anthropic 官方聲明（「human error, not a security breach」）仍是官方說法，無撤回或修正。</li><li><strong>KAIROS 仍未正式發布</strong>：Claude Code v2.1.128 至 v2.1.150 的 changelog 中均無 KAIROS 正式啟用的記錄，截至 2026-05-25 仍未釋出。</li><li><strong>autoDream 仍未正式發布</strong>：同上，v2.1.150 changelog 無相關項目；Auto Memory（append-only）+ memory-compactor 仍是現行記憶架構。</li><li><strong>四階段整合循環</strong>（autoDream Orient → Gather → Consolidate → Prune）的技術說明仍準確，且已被 workspace <code>memory-compactor</code> agent 手動模擬（見 <code>implementation-research</code> 報告）。</li><li><strong>15 秒 blocking budget 與 periodic tick 設計</strong>：KAIROS 架構描述仍與已知洩漏代碼一致；無新的官方資料推翻此設計。</li><li><strong>三層記憶系統</strong>（Session context / Auto Memory / autoDream output）描述仍準確，反映 Claude Code 的設計意圖。</li><li><strong>axios 供應鏈攻擊</strong>（1.14.1、0.30.4）事件已確認，建議改用 Native Installer 仍是有效的安全建議。</li><li><strong>ULTRAPLAN 描述</strong>（30 分鐘遠端規劃 session、Opus 模型、非同步執行）已在 v2.1.149 得到間接確認（bug fix 條目明確提及 <code>/ultraplan</code> 命令存在）。</li></ul><h3 id="⚠️-可能過期或需要修正的資訊" tabindex="-1">⚠️ 可能過期或需要修正的資訊 <a class="header-anchor" href="#⚠️-可能過期或需要修正的資訊" aria-label="Permalink to &quot;⚠️ 可能過期或需要修正的資訊&quot;">​</a></h3><ul><li><strong>ULTRAPLAN 底層模型</strong>：報告寫「使用 Opus 4.6」；Claude Code 於 2026 年將 Opus 4.7 設為新預設，ULTRAPLAN 所用模型版本可能已升級至 Opus 4.7，但無官方確認。</li><li><strong>「150+ KAIROS 引用 = production-ready」推論</strong>：從洩漏時間點（2026-03-31）至今已近 2 個月，KAIROS 仍未上線，顯示「production-ready」判斷偏樂觀——更準確的描述是「功能完整但受 feature flag 管控，發布時程未定」。</li><li><strong>Data poisoning / undercover mode 描述</strong>：此段描述基於洩漏代碼解讀，Anthropic 未官方確認這些功能的具體用途。2 個月後無後續報導跟進，業界關注度已降低，但技術事實描述仍成立。</li><li><strong>Claude Code ARR $25 億</strong>（同步更新節）：係市場分析估計值，非官方財報數字；2026-05-25 無法確認是否有更新估計。</li><li><strong>BUDDY 功能</strong>（Tamagotchi 8 天實驗）：描述仍準確，但屬歷史事件，無後續演進。</li></ul><h3 id="🆕-新發現補充" tabindex="-1">🆕 新發現補充 <a class="header-anchor" href="#🆕-新發現補充" aria-label="Permalink to &quot;🆕 新發現補充&quot;">​</a></h3><ul><li><strong><code>/ultraplan</code> bug fix（v2.1.149）</strong>：明確記錄「Fixed <code>/ultraplan</code> and remote session creation failing with &#39;Could not capture uncommitted changes&#39;」，確認 ULTRAPLAN 已作為可用命令存在，且已修復一個影響遠端 session 創建的 bug。這是本報告發布後最重要的具體進展。</li><li><strong><code>/goal</code> 命令（v2.1.139，同步更新節）</strong>：提供 KAIROS 部分能力（跨 turns 持續執行至條件達成）；截至 v2.1.150，此命令仍是 KAIROS 最接近的已發布替代品。</li><li><strong>Claude Code v2.1.149 <code>/usage</code> 分項</strong>：Sub-agent 成本現可獨立追蹤，對 autoDream/KAIROS 等多層代理架構的成本透明度有直接改善意義。</li><li><strong>Bun bug #28001 後續</strong>：洩漏同步更新節提及此 bug 是洩漏根因之一（2026-03-11 提交）；後續是否已在 Bun 主線修復，無即時資料，建議持續關注。</li><li><strong>競品實作進展</strong>：報告 Part 8.3 預測「其他 AI 團隊將實作 KAIROS-like daemon modes」——截至 2026-05-25，OpenAI Codex CLI 和 Gemini CLI 均已有持續性 agent 模式的相關公告，預測方向正確，但具體實作深度未能驗證。</li></ul>',181)])])}const m=a(n,[["render",r]]);export{p as __pageData,m as default};
